parameters.jsCode:
const page = $input.item.json;
const props = page.properties || {};
const formData = $('n8n Form Submit Reel Request').item.json;

function text(prop) {
  if (!prop) return '';
  if (prop.type === 'title' && prop.title) return prop.title.map(function(t){ return t.plain_text; }).join('');
  if (prop.type === 'rich_text' && prop.rich_text) return prop.rich_text.map(function(t){ return t.plain_text; }).join('');
  if (prop.type === 'url') return prop.url || '';
  if (prop.type === 'select' && prop.select) return prop.select.name || '';
  if (prop.type === 'multi_select' && prop.multi_select) return prop.multi_select.map(function(s){ return s.name; }).join(', ');
  return '';
}

const status = text(props['Status']);
if (status === 'Published') throw new Error('Notion page is already Published. Aborting to prevent duplicate post.');
if (status === 'Failed')    throw new Error('Notion page is marked Failed. Fix the video before resubmitting.');
if (status === 'Rejected')  throw new Error('Notion page was previously Rejected.');

const videoUrl = text(props['Video URL']);
if (!videoUrl) throw new Error('Notion page has no Video URL property. Cannot publish.');

return {
  notion_page_id: page.id,
  title:          text(props['Title']),
  video_url:      videoUrl,
  cover_url:      text(props['Cover URL']) || '',
  description:    text(props['Description']) || '',
  tags:           text(props['Tags']) || '',
  caption_tone:   formData['Caption Tone'] || 'storytelling',
  ig_user_id:     $env.IG_USER_ID
};

const d = $input.item.json;
const tone = d.caption_tone || 'storytelling';

const toneGuide = {
  hype:         'Energetic, punchy, 1–2 fire emojis, very short sentences. High energy.',
  minimal:      'Clean and minimal. No emojis. One powerful sentence max.',
  storytelling: 'Warm, narrative, and personal. Makes the viewer feel something real.'
};

const tagBlock = d.tags
  ? d.tags.split(',').map(function(t){
      t = t.trim(); return t.startsWith('#') ? t : '#' + t;
    }).join(' ')
  : '#reels #instagram #content #fyp';

let finalCaption;
try {
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type':      'application/json',
      'x-api-key':         $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model:      'claude-haiku-4-5',
      max_tokens: 400,
      messages: [{
        role: 'user',
        content: [
          'Write an Instagram Reel caption.',
          'Title: ' + d.title,
          'Description: ' + (d.description || 'none'),
          'Tags to include: ' + tagBlock,
          'Tone: ' + tone + ' — ' + (toneGuide[tone] || ''),
          'End with a short CTA to follow or save.',
          'Max 2200 characters. Output ONLY the caption text, no preamble.'
        ].join('\n')
      }]
    })
  });
  const ai = await res.json();
  finalCaption = (ai.content && ai.content[0] && ai.content[0].text)
    ? ai.content[0].text.trim()
    : null;
} catch(e) {
  finalCaption = null;
}

if (!finalCaption) {
  finalCaption = (d.title ? d.title + '\n\n' : '') +
    (d.description ? d.description.trim() + '\n\n' : '') +
    'Follow for more.\n\n' + tagBlock;
}

if (finalCaption.length > 2200) finalCaption = finalCaption.substring(0, 2196) + '...';

return { ...d, final_caption: finalCaption };

const upload = $input.item.json;
const prev = $('Code Claude AI Caption').item.json;
const publicVideoUrl = upload.public_url || upload.url || upload.file_url || upload.cdn_url || '';
if (!publicVideoUrl) throw new Error('Video CDN upload returned no public URL. Keys: ' + JSON.stringify(Object.keys(upload)));
return { ...prev, public_video_url: publicVideoUrl };

const coverUpload = $input.item.json;
const videoData = $('Code Store Video CDN URL').item.json;
const publicCoverUrl = coverUpload.public_url || coverUpload.url || coverUpload.file_url || coverUpload.cdn_url || '';
return {
  notion_page_id:   videoData.notion_page_id,
  title:            videoData.title,
  ig_user_id:       videoData.ig_user_id,
  final_caption:    videoData.final_caption,
  public_video_url: videoData.public_video_url,
  public_cover_url: publicCoverUrl,
  retry_count:      0
};

