const d = $input.item.json;
if (d.retry_count < 15) {
  return {
    retry_count:      d.retry_count,
    status_code:      d.status_code,
    container_id:     d.container_id,
    notion_page_id:   d.notion_page_id,
    ig_user_id:       d.ig_user_id,
    title:            d.title,
    public_video_url: d.public_video_url,
    public_cover_url: d.public_cover_url
  };
}
throw new Error(
  'Reel encoding failed after 15 attempts.' +
  ' Status: ' + d.status_code +
  ' | Notion: ' + d.notion_page_id +
  ' | Title: ' + d.title
);

